package com.nhom2.config

import io.github.cdimascio.dotenv.dotenv
import org.jetbrains.exposed.sql.Database

object DatabaseConfig {
    fun init() {
        val env = dotenv { ignoreIfMissing = true }

        Database.connect(
            url = env["DATABASE_URL"],
            driver = "org.postgresql.Driver",
            user = env["DATABASE_USER"],
            password = env["DATABASE_PASSWORD"]
        )
        println("Database connected successfully")
    }
}

package com.nhom2.config

import io.github.cdimascio.dotenv.dotenv
import org.jetbrains.exposed.sql.Database

object DatabaseConfig {
    fun init() {
        val env = dotenv { ignoreIfMissing = true }

        val dbUrl = env["DATABASE_URL"] ?: throw IllegalStateException("DATABASE_URL environment variable is required")
        val dbUser = env["DATABASE_USER"] ?: throw IllegalStateException("DATABASE_USER environment variable is required")
        val dbPassword = env["DATABASE_PASSWORD"] ?: throw IllegalStateException("DATABASE_PASSWORD environment variable is required")

        Database.connect(
            url = dbUrl,
            driver = "org.postgresql.Driver",
            user = dbUser,
            password = dbPassword
        )
        println("Database connected successfully")
    }
}
